(window.webpackJsonp=window.webpackJsonp||[]).push([[15],{642:function(n,t){n.exports='\x3c!-- \ntitle: 01-CPP入门\nsort: \n--\x3e \n\n# C++入门\n\n## 第一个C++程序\n\n```c++\n#include<iostream>\nusing namespace std;\n\nint main()\n{\n\n\tcout << "Hello world" << endl;\n\n\tsystem("pause");\n\n\treturn 0;\n}\n```\n\n## 入门\n\n```cpp\n// 字符串\nstring str = "hello world";\ncout << str << endl;\t\t// 输出\n// 输入\ncout << "请输入：" << endl;\ncin >> str;\ncout << str << endl;\n// 三目\nc = a > b ? a : b;\n// 结构体\nstruct student {\n\tstring name;  \n\tint age;      \n\tint score;    \n};\n// 结构体数组\nstruct student arr[3]=\n{\n\t{"张三",18,80 },\n\t{"李四",19,60 },\n\t{"王五",20,70 }\n};\n// 结构体指针\nstruct student * p = &arr[0];\np->score=75;\n```\n\n## std\n\n> 标准库中函数或对象，都是在std命名空间中定义的。\n>\n> 调用标准库需要写上std\n\n#### `::`\n\n1. 标明类的变量、函数。\n\n   `Human::setName(char* name);`\n\n2. 命名空间作用域，注明命名空间。\n\n   `std::cout << "Hello World" << std::endl;`\n\n3. 全局作用域，名称一样时调用全局函数\n\n```c++\n// 命名空间::类::方法\nIR::Statement::toJSON(){}\n```\n\n'}}]);